@app.post("/admin/tokens", response_model=TokenResponse)
async def create_token(
    token_request: TokenCreateRequest,
    redis_conn: redis.Redis = Depends(get_redis),
):
    """
    Create a new OAuth token and store it in Redis.
    In production, this would be behind admin authentication.
    """
    # Generate a cryptographically secure token
    raw_token = secrets.token_urlsafe(48)

    # Hash the token for storage
    token_hash = _hash_token(raw_token)
    redis_key = f"{TOKEN_PREFIX}{token_hash}"

    ttl = min(token_request.ttl, 86400)  # Max 24 hours
    expires_at = time.time() + ttl

    token_data = {
        "user_id": token_request.user_id,
        "scopes": ",".join(token_request.scopes),
        "client_id": token_request.client_id,
        "expires_at": str(expires_at),
        "created_at": str(time.time()),
    }

    try:
        pipe = redis_conn.pipeline()
        pipe.hset(redis_key, mapping=token_data)
        pipe.expire(redis_key, ttl)
        await pipe.execute()
    except Exception as e:
        raise HTTPException(
            status_code=500, detail=f"Failed to create token: {e}"
        )

    return TokenResponse(
        access_token=raw_token,
        token_type="bearer",
        expires_in=ttl,
    )


